export const getProvinces = (): string[] => {
  return thailandLocations.map(loc => loc.province).sort((a, b) => a.localeCompare(b, 'th'));
};

export const getDistricts = (province: string): string[] => {
  const loc = thailandLocations.find(l => l.province === province);
  return loc ? loc.districts.map(d => d.name).sort((a, b) => a.localeCompare(b, 'th')) : [];
};

export const getSubdistricts = (province: string, district: string): string[] => {
  const loc = thailandLocations.find(l => l.province === province);
  if (!loc) return [];
  const dist = loc.districts.find(d => d.name === district);
  return dist ? dist.subdistricts.sort((a, b) => a.localeCompare(b, 'th')) : [];
};
